/* Vargas Arts navigation helper. Lightweight Popper fallback retained for Bootstrap compatibility. */
(function(){
  function addVideosNavTab(){
    var navLists=document.querySelectorAll('.navbar-nav');
    navLists.forEach(function(nav){
      if(nav.querySelector('a[href="./videos.html"],a[href="videos.html"]')) return;
      var artForSale=nav.querySelector('a[href="./sales.html"],a[href="sales.html"]');
      var about=nav.querySelector('a[href="./about.html"],a[href="about.html"]');
      var contact=nav.querySelector('a[href="./contact.html"],a[href="contact.html"]');
      if(!artForSale&&!about&&!contact) return;
      var li=document.createElement('li');
      li.className='nav-item';
      var a=document.createElement('a');
      a.className='nav-link';
      a.href='./videos.html';
      a.textContent='Videos';
      if(/videos\.html?$/i.test(window.location.pathname)) a.className+=' active';
      li.appendChild(a);
      var target=artForSale||about||contact;
      if(target&&target.parentNode){nav.insertBefore(li,target.parentNode);}else{nav.appendChild(li);}
    });
  }
  if(document.readyState==='loading'){
    document.addEventListener('DOMContentLoaded',addVideosNavTab);
  }else{
    addVideosNavTab();
  }
  window.addEventListener('load',addVideosNavTab);
  if(!window.Popper){
    window.Popper=function(){return{destroy:function(){},update:function(){},scheduleUpdate:function(){}}};
    window.Popper.Defaults={};
  }
})();
